package com.example.oidc.config;

import com.example.oidc.model.UserSession;
import com.example.oidc.service.UserSessionService;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.security.oauth2.client.oidc.userinfo.OidcUserRequest;
import org.springframework.security.oauth2.client.oidc.userinfo.OidcUserService;
import org.springframework.security.oauth2.core.OAuth2AuthenticationException;
import org.springframework.security.oauth2.core.oidc.user.OidcUser;

public class CustomOidcUserService extends OidcUserService {

    private static final Logger logger = LoggerFactory.getLogger(CustomOidcUserService.class);

    @Autowired
    private UserSessionService userSessionService;

    @Override
    public OidcUser loadUser(OidcUserRequest userRequest) throws OAuth2AuthenticationException {
        OidcUser oidcUser = super.loadUser(userRequest);

        logger.info("OIDC User authenticated: sub={}", oidcUser.getSubject());

        // Parse id_token claims and create user session
        UserSession session = userSessionService.createSessionFromIdToken(oidcUser, userRequest);
        logger.info("User session created for: {}", session.getEmail());

        return oidcUser;
    }
}

