package com.example.oidc.service;

import com.example.oidc.model.UserSession;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.security.oauth2.client.oidc.userinfo.OidcUserRequest;
import org.springframework.security.oauth2.core.oidc.OidcIdToken;
import org.springframework.security.oauth2.core.oidc.user.OidcUser;
import org.springframework.stereotype.Service;

import java.time.Instant;
import java.util.*;
import java.util.concurrent.ConcurrentHashMap;

@Service
public class UserSessionService {

    private static final Logger logger = LoggerFactory.getLogger(UserSessionService.class);

    // In-memory session store (use Redis or database in production)
    private final Map<String, UserSession> sessionStore = new ConcurrentHashMap<>();

    public UserSession createSessionFromIdToken(OidcUser oidcUser, OidcUserRequest userRequest) {
        OidcIdToken idToken = oidcUser.getIdToken();
        Map<String, Object> claims = idToken.getClaims();

        UserSession session = new UserSession();
        session.setSessionId(UUID.randomUUID().toString());

        // Parse standard OIDC claims from id_token
        session.setSubject(idToken.getSubject());
        session.setEmail(idToken.getEmail());
        session.setEmailVerified(idToken.getEmailVerified() != null && idToken.getEmailVerified());
        session.setName(idToken.getFullName());
        session.setGivenName(idToken.getGivenName());
        session.setFamilyName(idToken.getFamilyName());
        session.setPreferredUsername(getClaimAsString(claims, "preferred_username"));
        session.setPicture(idToken.getPicture());
        session.setLocale(getClaimAsString(claims, "locale"));

        // Extract roles from claims (common in Keycloak, Auth0, etc.)
        session.setRoles(extractRoles(claims));

        // Store tokens
        session.setAccessToken(userRequest.getAccessToken().getTokenValue());
        session.setIdToken(idToken.getTokenValue());

        if (userRequest.getAccessToken().getExpiresAt() != null) {
            session.setAccessTokenExpiresAt(userRequest.getAccessToken().getExpiresAt());
        }

        // Store additional custom claims
        Map<String, Object> additionalClaims = new HashMap<>(claims);
        // Remove standard claims to keep only custom ones
        Set<String> standardClaims = Set.of("sub", "email", "email_verified", "name",
            "given_name", "family_name", "preferred_username", "picture", "locale",
            "iss", "aud", "exp", "iat", "auth_time", "nonce", "acr", "amr", "azp",
            "at_hash", "c_hash");
        standardClaims.forEach(additionalClaims::remove);
        session.setAdditionalClaims(additionalClaims);

        session.setSessionCreatedAt(Instant.now());
        session.setLastAccessedAt(Instant.now());

        // Store session
        sessionStore.put(session.getSessionId(), session);
        sessionStore.put(session.getSubject(), session);

        logger.info("Created session for user: sub={}, email={}, name={}, roles={}",
            session.getSubject(), session.getEmail(), session.getName(), session.getRoles());

        logIdTokenClaims(claims);

        return session;
    }

    @SuppressWarnings("unchecked")
    private List<String> extractRoles(Map<String, Object> claims) {
        List<String> roles = new ArrayList<>();

        // Try realm_access.roles (Keycloak format)
        Object realmAccess = claims.get("realm_access");
        if (realmAccess instanceof Map) {
            Object realmRoles = ((Map<String, Object>) realmAccess).get("roles");
            if (realmRoles instanceof List) {
                roles.addAll((List<String>) realmRoles);
            }
        }

        // Try roles claim directly
        Object directRoles = claims.get("roles");
        if (directRoles instanceof List) {
            roles.addAll((List<String>) directRoles);
        }

        // Try groups claim (Auth0 format)
        Object groups = claims.get("groups");
        if (groups instanceof List) {
            roles.addAll((List<String>) groups);
        }

        return roles;
    }

    private String getClaimAsString(Map<String, Object> claims, String claimName) {
        Object value = claims.get(claimName);
        return value != null ? value.toString() : null;
    }

    private void logIdTokenClaims(Map<String, Object> claims) {
        logger.debug("ID Token claims:");
        claims.forEach((key, value) ->
            logger.debug("  {} = {}", key, value));
    }

    public Optional<UserSession> getSessionById(String sessionId) {
        UserSession session = sessionStore.get(sessionId);
        if (session != null) {
            session.setLastAccessedAt(Instant.now());
        }
        return Optional.ofNullable(session);
    }

    public Optional<UserSession> getSessionBySubject(String subject) {
        UserSession session = sessionStore.get(subject);
        if (session != null) {
            session.setLastAccessedAt(Instant.now());
        }
        return Optional.ofNullable(session);
    }

    public void removeSession(String sessionId) {
        UserSession session = sessionStore.remove(sessionId);
        if (session != null) {
            sessionStore.remove(session.getSubject());
            logger.info("Removed session for user: {}", session.getSubject());
        }
    }

    public void removeSessionBySubject(String subject) {
        UserSession session = sessionStore.remove(subject);
        if (session != null) {
            sessionStore.remove(session.getSessionId());
            logger.info("Removed session for user: {}", subject);
        }
    }

    public Collection<UserSession> getAllActiveSessions() {
        return sessionStore.values();
    }
}

