package com.example.oidc.service;

import com.example.oidc.config.OidcProviderConfig;
import com.nimbusds.jwt.JWT;
import com.nimbusds.jwt.JWTClaimsSet;
import com.nimbusds.jwt.JWTParser;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.http.*;
import org.springframework.stereotype.Service;
import org.springframework.util.LinkedMultiValueMap;
import org.springframework.util.MultiValueMap;
import org.springframework.web.client.RestTemplate;

import java.text.ParseException;
import java.util.Base64;
import java.util.Map;

@Service
public class TokenExchangeService {

    private static final Logger logger = LoggerFactory.getLogger(TokenExchangeService.class);

    private final OidcProviderConfig oidcProviderConfig;
    private final RestTemplate restTemplate;

    public TokenExchangeService(OidcProviderConfig oidcProviderConfig) {
        this.oidcProviderConfig = oidcProviderConfig;
        this.restTemplate = new RestTemplate();
    }

    /**
     * Exchange an authorization code for tokens at the token endpoint.
     */
    @SuppressWarnings("unchecked")
    public Map<String, Object> exchangeAuthorizationCode(String authorizationCode, String redirectUri) {
        logger.info("Exchanging authorization code for tokens at: {}", oidcProviderConfig.getTokenUri());

        HttpHeaders headers = new HttpHeaders();
        headers.setContentType(MediaType.APPLICATION_FORM_URLENCODED);

        // Add Basic auth header
        String credentials = oidcProviderConfig.getClientId() + ":" + oidcProviderConfig.getClientSecret();
        String encodedCredentials = Base64.getEncoder().encodeToString(credentials.getBytes());
        headers.set("Authorization", "Basic " + encodedCredentials);

        MultiValueMap<String, String> body = new LinkedMultiValueMap<>();
        body.add("grant_type", "authorization_code");
        body.add("code", authorizationCode);
        body.add("redirect_uri", redirectUri != null ? redirectUri : oidcProviderConfig.getRedirectUri());

        HttpEntity<MultiValueMap<String, String>> request = new HttpEntity<>(body, headers);

        try {
            ResponseEntity<Map> response = restTemplate.exchange(
                oidcProviderConfig.getTokenUri(),
                HttpMethod.POST,
                request,
                Map.class
            );

            if (response.getStatusCode() == HttpStatus.OK && response.getBody() != null) {
                Map<String, Object> tokenResponse = response.getBody();
                logger.info("Successfully exchanged authorization code for tokens");

                // Parse the id_token if present
                if (tokenResponse.containsKey("id_token")) {
                    parseAndLogIdToken((String) tokenResponse.get("id_token"));
                }

                return tokenResponse;
            } else {
                logger.error("Token exchange failed with status: {}", response.getStatusCode());
                throw new RuntimeException("Token exchange failed");
            }
        } catch (Exception e) {
            logger.error("Error during token exchange: {}", e.getMessage(), e);
            throw new RuntimeException("Token exchange failed", e);
        }
    }

    /**
     * Refresh an access token using a refresh token.
     */
    @SuppressWarnings("unchecked")
    public Map<String, Object> refreshToken(String refreshToken) {
        logger.info("Refreshing access token at: {}", oidcProviderConfig.getTokenUri());

        HttpHeaders headers = new HttpHeaders();
        headers.setContentType(MediaType.APPLICATION_FORM_URLENCODED);

        String credentials = oidcProviderConfig.getClientId() + ":" + oidcProviderConfig.getClientSecret();
        String encodedCredentials = Base64.getEncoder().encodeToString(credentials.getBytes());
        headers.set("Authorization", "Basic " + encodedCredentials);

        MultiValueMap<String, String> body = new LinkedMultiValueMap<>();
        body.add("grant_type", "refresh_token");
        body.add("refresh_token", refreshToken);

        HttpEntity<MultiValueMap<String, String>> request = new HttpEntity<>(body, headers);

        try {
            ResponseEntity<Map> response = restTemplate.exchange(
                oidcProviderConfig.getTokenUri(),
                HttpMethod.POST,
                request,
                Map.class
            );

            if (response.getStatusCode() == HttpStatus.OK && response.getBody() != null) {
                logger.info("Successfully refreshed access token");
                return response.getBody();
            } else {
                logger.error("Token refresh failed with status: {}", response.getStatusCode());
                throw new RuntimeException("Token refresh failed");
            }
        } catch (Exception e) {
            logger.error("Error during token refresh: {}", e.getMessage(), e);
            throw new RuntimeException("Token refresh failed", e);
        }
    }

    /**
     * Fetch user info from the UserInfo endpoint.
     */
    @SuppressWarnings("unchecked")
    public Map<String, Object> fetchUserInfo(String accessToken) {
        logger.info("Fetching user info from: {}", oidcProviderConfig.getUserInfoUri());

        HttpHeaders headers = new HttpHeaders();
        headers.setBearerAuth(accessToken);

        HttpEntity<Void> request = new HttpEntity<>(headers);

        try {
            ResponseEntity<Map> response = restTemplate.exchange(
                oidcProviderConfig.getUserInfoUri(),
                HttpMethod.GET,
                request,
                Map.class
            );

            if (response.getStatusCode() == HttpStatus.OK && response.getBody() != null) {
                logger.info("Successfully fetched user info");
                return response.getBody();
            } else {
                logger.error("UserInfo request failed with status: {}", response.getStatusCode());
                throw new RuntimeException("UserInfo request failed");
            }
        } catch (Exception e) {
            logger.error("Error fetching user info: {}", e.getMessage(), e);
            throw new RuntimeException("UserInfo request failed", e);
        }
    }

    /**
     * Parse and log ID token claims using Nimbus JOSE+JWT.
     */
    public JWTClaimsSet parseAndLogIdToken(String idTokenValue) {
        try {
            JWT jwt = JWTParser.parse(idTokenValue);
            JWTClaimsSet claimsSet = jwt.getJWTClaimsSet();

            logger.info("ID Token Claims:");
            logger.info("  Issuer: {}", claimsSet.getIssuer());
            logger.info("  Subject: {}", claimsSet.getSubject());
            logger.info("  Audience: {}", claimsSet.getAudience());
            logger.info("  Expiration: {}", claimsSet.getExpirationTime());
            logger.info("  Issued At: {}", claimsSet.getIssueTime());

            Object email = claimsSet.getClaim("email");
            if (email != null) {
                logger.info("  Email: {}", email);
            }

            Object name = claimsSet.getClaim("name");
            if (name != null) {
                logger.info("  Name: {}", name);
            }

            return claimsSet;
        } catch (ParseException e) {
            logger.error("Failed to parse ID token: {}", e.getMessage(), e);
            throw new RuntimeException("Failed to parse ID token", e);
        }
    }
}

