package com.example.oidc.controller;

import com.example.oidc.config.OidcProviderConfig;
import com.example.oidc.service.TokenExchangeService;
import com.example.oidc.service.UserSessionService;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.stereotype.Controller;
import org.springframework.ui.Model;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.RequestParam;

import jakarta.servlet.http.HttpSession;
import java.util.Map;

@Controller
public class AuthController {

    private static final Logger logger = LoggerFactory.getLogger(AuthController.class);

    private final OidcProviderConfig oidcProviderConfig;
    private final TokenExchangeService tokenExchangeService;
    private final UserSessionService userSessionService;

    public AuthController(OidcProviderConfig oidcProviderConfig,
                          TokenExchangeService tokenExchangeService,
                          UserSessionService userSessionService) {
        this.oidcProviderConfig = oidcProviderConfig;
        this.tokenExchangeService = tokenExchangeService;
        this.userSessionService = userSessionService;
    }

    @GetMapping("/")
    public String home() {
        return "home";
    }

    @GetMapping("/login")
    public String login(Model model) {
        model.addAttribute("loginUrl", "/oauth2/authorization/oidc-provider");
        return "login";
    }

    /**
     * Manual callback handler for custom authorization code exchange
     * (alternative to Spring Security's built-in handler).
     */
    @GetMapping("/auth/callback")
    public String handleCallback(
            @RequestParam(value = "code", required = false) String code,
            @RequestParam(value = "state", required = false) String state,
            @RequestParam(value = "error", required = false) String error,
            @RequestParam(value = "error_description", required = false) String errorDescription,
            HttpSession httpSession,
            Model model) {

        if (error != null) {
            logger.error("OIDC authentication error: {} - {}", error, errorDescription);
            model.addAttribute("error", error);
            model.addAttribute("errorDescription", errorDescription);
            return "error";
        }

        if (code == null) {
            logger.error("No authorization code received");
            model.addAttribute("error", "No authorization code received");
            return "error";
        }

        logger.info("Received authorization code, exchanging for tokens...");

        try {
            // Exchange authorization code for tokens
            Map<String, Object> tokenResponse = tokenExchangeService.exchangeAuthorizationCode(
                code, oidcProviderConfig.getRedirectUri());

            String accessToken = (String) tokenResponse.get("access_token");
            String idToken = (String) tokenResponse.get("id_token");
            String refreshToken = (String) tokenResponse.get("refresh_token");

            // Store tokens in HTTP session
            httpSession.setAttribute("access_token", accessToken);
            httpSession.setAttribute("id_token", idToken);
            httpSession.setAttribute("refresh_token", refreshToken);

            // Parse ID token claims
            if (idToken != null) {
                var claims = tokenExchangeService.parseAndLogIdToken(idToken);
                httpSession.setAttribute("user_subject", claims.getSubject());
                httpSession.setAttribute("user_email", claims.getClaim("email"));
                httpSession.setAttribute("user_name", claims.getClaim("name"));
            }

            // Optionally fetch user info
            if (accessToken != null) {
                try {
                    Map<String, Object> userInfo = tokenExchangeService.fetchUserInfo(accessToken);
                    httpSession.setAttribute("user_info", userInfo);
                } catch (Exception e) {
                    logger.warn("Could not fetch user info: {}", e.getMessage());
                }
            }

            return "redirect:/dashboard";
        } catch (Exception e) {
            logger.error("Token exchange failed: {}", e.getMessage(), e);
            model.addAttribute("error", "Authentication failed: " + e.getMessage());
            return "error";
        }
    }
}

