package com.example.oidc.controller;

import com.example.oidc.model.UserSession;
import com.example.oidc.service.UserSessionService;
import org.springframework.security.core.annotation.AuthenticationPrincipal;
import org.springframework.security.oauth2.core.oidc.user.OidcUser;
import org.springframework.stereotype.Controller;
import org.springframework.ui.Model;
import org.springframework.web.bind.annotation.GetMapping;

import java.util.Optional;

@Controller
public class DashboardController {

    private final UserSessionService userSessionService;

    public DashboardController(UserSessionService userSessionService) {
        this.userSessionService = userSessionService;
    }

    @GetMapping("/dashboard")
    public String dashboard(@AuthenticationPrincipal OidcUser oidcUser, Model model) {
        if (oidcUser != null) {
            model.addAttribute("userName", oidcUser.getFullName());
            model.addAttribute("userEmail", oidcUser.getEmail());
            model.addAttribute("userSubject", oidcUser.getSubject());
            model.addAttribute("userPicture", oidcUser.getPicture());
            model.addAttribute("idTokenClaims", oidcUser.getIdToken().getClaims());
            model.addAttribute("userInfoClaims", oidcUser.getUserInfo() != null ?
                oidcUser.getUserInfo().getClaims() : null);

            // Get stored session info
            Optional<UserSession> sessionOpt = userSessionService.getSessionBySubject(oidcUser.getSubject());
            sessionOpt.ifPresent(session -> {
                model.addAttribute("userSession", session);
                model.addAttribute("roles", session.getRoles());
                model.addAttribute("sessionCreated", session.getSessionCreatedAt());
            });
        }

        return "dashboard";
    }

    @GetMapping("/profile")
    public String profile(@AuthenticationPrincipal OidcUser oidcUser, Model model) {
        if (oidcUser != null) {
            model.addAttribute("user", oidcUser);
            model.addAttribute("claims", oidcUser.getClaims());
        }
        return "profile";
    }
}

