// ============================================================
package com.example.oidc.controller;

import com.example.oidc.model.UserSession;
import com.example.oidc.service.UserSessionService;
import org.springframework.http.ResponseEntity;
import org.springframework.security.core.annotation.AuthenticationPrincipal;
import org.springframework.security.oauth2.core.oidc.user.OidcUser;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.RequestMapping;
import org.springframework.web.bind.annotation.RestController;

import java.util.HashMap;
import java.util.Map;
import java.util.Optional;

@RestController
@RequestMapping("/api")
public class UserInfoRestController {

    private final UserSessionService userSessionService;

    public UserInfoRestController(UserSessionService userSessionService) {
        this.userSessionService = userSessionService;
    }

    @GetMapping("/user")
    public ResponseEntity<Map<String, Object>> getCurrentUser(@AuthenticationPrincipal OidcUser oidcUser) {
        if (oidcUser == null) {
            return ResponseEntity.status(401).build();
        }

        Map<String, Object> userInfo = new HashMap<>();
        userInfo.put("subject", oidcUser.getSubject());
        userInfo.put("email", oidcUser.getEmail());
        userInfo.put("name", oidcUser.getFullName());
        userInfo.put("picture", oidcUser.getPicture());
        userInfo.put("claims", oidcUser.getClaims());

        Optional<UserSession> sessionOpt = userSessionService.getSessionBySubject(oidcUser.getSubject());
        sessionOpt.ifPresent(session -> {
            userInfo.put("roles", session.getRoles());
            userInfo.put("sessionCreatedAt", session.getSessionCreatedAt().toString());
            userInfo.put("lastAccessedAt", session.getLastAccessedAt().toString());
            userInfo.put("accessTokenExpired", session.isAccessTokenExpired());
        });

        return ResponseEntity.ok(userInfo);
    }

    @GetMapping("/sessions")
    public ResponseEntity<?> getActiveSessions() {
        return ResponseEntity.ok(userSessionService.getAllActiveSessions());
    }
}

